65	// newDocAuditCommand surfaces structured integrity issues for CI and
66	// terminal use. Exits 0 when the graph is clean and 1 when any issue is
67	// detected, so CI can gate merges on a healthy graph.
68	func (f *CommandFactory) newDocAuditCommand() *cobra.Command {
69		cmd := &cobra.Command{
70			Use:     "audit",
71			Short:   "Audit document graph integrity (duplicates, missing deps, broken id_to_path)",
72			Aliases: []string{"integrity"},
73			Args:    cobra.NoArgs,
74			RunE: func(cmd *cobra.Command, args []string) error {
75				graph, err := f.buildDocGraph()
76				if err != nil {
77					return err
78				}
79				asJSON, _ := cmd.Flags().GetBool("json")
80				exitZero, _ := cmd.Flags().GetBool("exit-zero")
81				if asJSON {
82					enc := json.NewEncoder(cmd.OutOrStdout())
83					enc.SetIndent("", "  ")
84					if err := enc.Encode(graph.Issues); err != nil {
85						return err
86					}
87					if len(graph.Issues) == 0 || exitZero {
88						return nil
89					}
90					cmd.SilenceUsage = true
91					cmd.SilenceErrors = true
92					return NewExitError(ExitCodeGeneralError, "")
93				}
94				out := cmd.OutOrStdout()
95				if len(graph.Issues) == 0 {
96					fmt.Fprintln(out, "Document graph is clean.")
97					return nil
98				}
99				groups := map[docgraph.IssueKind][]docgraph.GraphIssue{}
100				order := []docgraph.IssueKind{}
101				for _, issue := range graph.Issues {
102					if _, ok := groups[issue.Kind]; !ok {
103						order = append(order, issue.Kind)
104					}
105					groups[issue.Kind] = append(groups[issue.Kind], issue)
106				}
107				sort.Slice(order, func(i, j int) bool { return order[i] < order[j] })
108				for _, kind := range order {
109					bucket := groups[kind]
110					fmt.Fprintf(out, "%s (%d):\n", kind, len(bucket))
111					for _, issue := range bucket {
112						fmt.Fprintf(out, "  - %s\n", issue.Message)
113					}
114				}
115				fmt.Fprintf(cmd.ErrOrStderr(), "\n%d integrity issue(s) found\n", len(graph.Issues))
116				// Return a typed ExitError so main() exits 1 without Cobra
117				// reprinting the (empty) error message or usage summary; the
118				// grouped issue list above is the user-facing report.
119				cmd.SilenceUsage = true
120				cmd.SilenceErrors = true
121				return NewExitError(ExitCodeGeneralError, "")
122			},
123		}
124		cmd.Flags().Bool("json", false, "Output issues as JSON")
125		cmd.Flags().Bool("exit-zero", false, "Always exit 0 after printing audit output")
126		return cmd
127	}
