224	
225				stamped, warnings, err := graph.Stamp(targets, time.Now())
226				if err != nil {
227					return err
228				}
229	
230				// Load config for auto-commit settings (best-effort; ignore errors).
231				var acCfg internalgit.AutoCommitConfig
232				if cfg, cfgErr := config.LoadWithWorkingDir(f.docRoot()); cfgErr == nil && cfg.Git != nil {
233					acCfg.AutoCommit = cfg.Git.AutoCommit
234					acCfg.CommitPrefix = cfg.Git.CommitPrefix
235				}
236	
237				for _, w := range warnings {
238					fmt.Fprintf(cmd.ErrOrStderr(), "warning: %s\n", w)
239				}
240				for _, id := range stamped {
241					doc, ok := graph.Documents[id]
242					path := id
243					if ok {
244						path = doc.Path
245					}
246					fmt.Fprintf(cmd.OutOrStdout(), "stamped %s\n", path)
247					autoCommitPath := path
248					if ok && !filepath.IsAbs(autoCommitPath) {
249						autoCommitPath = filepath.Join(graph.RootDir, autoCommitPath)
250					}
251					if _, acErr := internalgit.AutoCommit(autoCommitPath, id, "stamp reviewed", acCfg); acErr != nil {
252						fmt.Fprintf(cmd.ErrOrStderr(), "warning: auto-commit failed for %s: %v\n", path, acErr)
253					}
254				}
255				return nil
256			},
257		}
