337	func (f *CommandFactory) newDocMigrateCommand() *cobra.Command {
338		cmd := &cobra.Command{
339			Use:   "migrate [path]",
340			Short: "Convert legacy `dun:` frontmatter to `ddx:`",
341			Long: `Migrate markdown documents by replacing legacy ` + "`" + `dun:` + "`" + ` frontmatter namespaces with ` + "`" + `ddx:` + "`" + `.
342	
343	Examples:
344	  ddx doc migrate
345	  ddx doc migrate docs/`,
346			Args: cobra.MaximumNArgs(1),
347			RunE: func(cmd *cobra.Command, args []string) error {
348				target := f.docRoot()
349				if len(args) == 1 {
350					target = args[0]
351				}
352	
353				_, err := os.Stat(target)
354				if err != nil {
355					return fmt.Errorf("path not found: %s", target)
356				}
357	
358				convertCount := 0
359				skipCount := 0
360	
361				err = filepath.WalkDir(target, func(path string, d fs.DirEntry, walkErr error) error {
362					if walkErr != nil {
363						return walkErr
364					}
365					if d.IsDir() {
366						return nil
367					}
368					if !strings.HasSuffix(d.Name(), ".md") {
369						return nil
370					}
371	
372					content, readErr := os.ReadFile(path)
373					if readErr != nil {
374						return readErr
375					}
376	
377					fm, body, parseErr := docgraph.ParseFrontmatter(content)
378					if parseErr != nil || !fm.HasFrontmatter || fm.Namespace != "dun" {
379						if parseErr != nil {
380							return parseErr
381						}
382						skipCount++
383						return nil
384					}
385	
386					didMigrate := docgraph.MigrateLegacyDunFrontmatter(fm.Raw)
387					if !didMigrate {
388						skipCount++
389						return nil
390					}
391	
392					frontmatterText, encodeErr := docgraph.EncodeFrontmatter(fm.Raw)
393					if encodeErr != nil {
394						return encodeErr
395					}
396	
397					updated := []byte(fmt.Sprintf("---\n%s\n---\n%s", frontmatterText, body))
398					if err := os.WriteFile(path, updated, 0644); err != nil {
399						return err
400					}
401					convertCount++
402					return nil
403				})
404				if err != nil {
405					return err
406				}
407	
408				fmt.Fprintf(cmd.OutOrStdout(), "migrated %d files, skipped %d files\n", convertCount, skipCount)
409				return nil
410			},
411		}
412		return cmd
413	}
