477	func (f *CommandFactory) newDocValidateCommand() *cobra.Command {
478		return &cobra.Command{
479			Use:   "validate",
480			Short: "Validate document graph (check for cycles, missing deps)",
481			Args:  cobra.NoArgs,
482			RunE: func(cmd *cobra.Command, args []string) error {
483				graph, err := f.buildDocGraph()
484				if err != nil {
485					return err
486				}
487				out := cmd.OutOrStdout()
488				hasDiagnostics := false
489				hasFatalIssue := false
490				for _, issue := range graph.Issues {
491					hasDiagnostics = true
492					if isDocValidateFatalIssue(issue.Kind) {
493						hasFatalIssue = true
494						fmt.Fprintf(out, "error: %s\n", issue.Message)
495						continue
496					}
497					fmt.Fprintf(out, "warning: %s\n", issue.Message)
498				}
499				for _, warning := range graph.ValidationWarnings {
500					hasDiagnostics = true
501					fmt.Fprintf(out, "warning: %s\n", warning)
502				}
503				if !hasDiagnostics {
504					fmt.Fprintln(cmd.OutOrStdout(), "Document graph is valid.")
505					return nil
506				}
507				if hasFatalIssue {
508					cmd.SilenceUsage = true
509					cmd.SilenceErrors = true
510					return NewExitError(ExitCodeGeneralError, "")
511				}
512				return nil
513			},
514		}
515	}
