563	func (f *CommandFactory) newDocHistoryCommand() *cobra.Command {
564		cmd := &cobra.Command{
565			Use:   "history <id>",
566			Short: "Show commit log for an artifact",
567			Args:  cobra.ExactArgs(1),
568			RunE: func(cmd *cobra.Command, args []string) error {
569				graph, err := f.buildDocGraph()
570				if err != nil {
571					return err
572				}
573				doc, ok := graph.Documents[args[0]]
574				if !ok {
575					return fmt.Errorf("document not found: %s", args[0])
576				}
577	
578				since, _ := cmd.Flags().GetString("since")
579				asJSON, _ := cmd.Flags().GetBool("json")
580	
581				gitArgs := []string{"log", "--follow", "--format=%H\t%ai\t%an\t%s"}
582				if since != "" {
583					gitArgs = append(gitArgs, since+"..HEAD")
584				}
585				gitArgs = append(gitArgs, "--", doc.Path)
586	
587				gitCmd := internalgit.Command(cmd.Context(), f.docRoot(), gitArgs...)
588				out, gitErr := gitCmd.Output()
589				if gitErr != nil {
590					if exitErr, ok2 := gitErr.(*exec.ExitError); ok2 {
591						if strings.Contains(string(exitErr.Stderr), "not a git repository") {
592							return fmt.Errorf("not a git repository")
593						}
594					}
595					return fmt.Errorf("git log failed: %w", gitErr)
596				}
597	
598				type commitEntry struct {
599					Hash    string `json:"hash"`
600					Date    string `json:"date"`
601					Author  string `json:"author"`
602					Message string `json:"message"`
603				}
604	
605				lines := strings.Split(strings.TrimRight(string(out), "\n"), "\n")
606				entries := make([]commitEntry, 0, len(lines))
607				for _, line := range lines {
608					if line == "" {
609						continue
610					}
611					parts := strings.SplitN(line, "\t", 4)
612					if len(parts) < 4 {
613						continue
614					}
615					hash := parts[0]
616					if len(hash) > 7 {
617						hash = hash[:7]
618					}
619					date := parts[1]
620					if len(date) > 10 {
621						date = date[:10]
622					}
623					entries = append(entries, commitEntry{
624						Hash:    hash,
625						Date:    date,
626						Author:  parts[2],
627						Message: parts[3],
628					})
629				}
630	
631				if asJSON {
632					enc := json.NewEncoder(cmd.OutOrStdout())
633					enc.SetIndent("", "  ")
634					return enc.Encode(entries)
635				}
636	
637				if len(entries) == 0 {
638					fmt.Fprintln(cmd.OutOrStdout(), "No commits found.")
639					return nil
640				}
641				for _, e := range entries {
