660					return err
661				}
662				doc, ok := graph.Documents[args[0]]
663				if !ok {
664					return fmt.Errorf("document not found: %s", args[0])
665				}
666	
667				var gitArgs []string
668				switch len(args) {
669				case 1:
670					gitArgs = []string{"diff", "--", doc.Path}
671				case 2:
672					gitArgs = []string{"diff", args[1], "--", doc.Path}
673				default:
674					gitArgs = []string{"diff", args[1], args[2], "--", doc.Path}
675				}
676	
677				gitCmd := internalgit.Command(cmd.Context(), f.docRoot(), gitArgs...)
678				out, gitErr := gitCmd.Output()
