698	func (f *CommandFactory) newDocChangedCommand() *cobra.Command {
699		cmd := &cobra.Command{
700			Use:   "changed",
701			Short: "List artifacts changed since a git ref",
702			Args:  cobra.NoArgs,
703			RunE: func(cmd *cobra.Command, args []string) error {
704				since, _ := cmd.Flags().GetString("since")
705				if since == "" {
706					since = "HEAD~5"
707				}
708				asJSON, _ := cmd.Flags().GetBool("json")
709	
710				out, gitErr := internalgit.Command(cmd.Context(), "", "diff", "--name-status", since, "HEAD").Output()
711				if gitErr != nil {
712					if exitErr, ok := gitErr.(*exec.ExitError); ok {
713						if strings.Contains(string(exitErr.Stderr), "not a git repository") {
714							return fmt.Errorf("not a git repository")
715						}
716					}
717					return fmt.Errorf("git diff failed: %w", gitErr)
718				}
719	
720				rootOut, gitErr := internalgit.Command(cmd.Context(), "", "rev-parse", "--show-toplevel").Output()
721				if gitErr != nil {
722					return fmt.Errorf("could not determine git root: %w", gitErr)
723				}
724				repoRoot := strings.TrimRight(string(rootOut), "\n")
725	
726				type changedEntry struct {
727					ID         string `json:"id"`
728					Path       string `json:"path"`
729					ChangeType string `json:"change_type"`
730				}
731	
732				graph, err := f.buildDocGraph()
733				if err != nil {
734					return err
735				}
736	
737				var entries []changedEntry
738				for _, line := range strings.Split(strings.TrimRight(string(out), "\n"), "\n") {
739					if line == "" {
740						continue
741					}
742					fields := strings.Fields(line)
743					if len(fields) < 2 {
744						continue
745					}
746					statusCode := fields[0]
747					relPath := fields[len(fields)-1]
748	
749					if !strings.HasSuffix(relPath, ".md") {
750						continue
751					}
752	
753					absPath := filepath.Join(repoRoot, relPath)
754					cleanPath := filepath.Clean(absPath)
755					graphKey := cleanPath
756					if rel, relErr := filepath.Rel(graph.RootDir, cleanPath); relErr == nil {
757						graphKey = rel
758					}
759	
760					var changeType string
761					switch {
762					case strings.HasPrefix(statusCode, "A"):
763						changeType = "added"
764					case strings.HasPrefix(statusCode, "D"):
765						changeType = "deleted"
766					default:
767						changeType = "modified"
768					}
769	
770					if changeType == "deleted" {
771						if id, ok := graph.PathToID[graphKey]; ok {
772							entries = append(entries, changedEntry{ID: id, Path: relPath, ChangeType: changeType})
773						}
774						continue
775					}
776	
777					if id, ok := graph.PathToID[graphKey]; ok {
778						entries = append(entries, changedEntry{ID: id, Path: relPath, ChangeType: changeType})
779						continue
780					}
781	
782					content, readErr := os.ReadFile(absPath)
783					if readErr != nil {
784						continue
785					}
786					fm, _, parseErr := docgraph.ParseFrontmatter(content)
787					if parseErr != nil || !fm.HasFrontmatter || fm.Doc.ID == "" {
788						continue
789					}
790					entries = append(entries, changedEntry{ID: fm.Doc.ID, Path: relPath, ChangeType: changeType})
791				}
792	
793				if asJSON {
794					enc := json.NewEncoder(cmd.OutOrStdout())
795					enc.SetIndent("", "  ")
796					return enc.Encode(entries)
797				}
798	
799				if len(entries) == 0 {
800					fmt.Fprintln(cmd.OutOrStdout(), "No artifact changes found.")
801					return nil
802				}
803				for _, e := range entries {
804					fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %s\n", e.ID, e.Path, e.ChangeType)
805				}
806				return nil
807			},
808		}
809		cmd.Flags().String("since", "", "Compare from this ref (default: HEAD~5)")
810		cmd.Flags().Bool("json", false, "Output as JSON")
811		return cmd
812	}
